    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //      createOrder
        //      {
        //          "OrderResponse": {"pair": "BtcNis", "HasError": False, "Error": "", "Message": ""},
        //          "NewOrder": {
        //              "created": 1505531577,
        //              "type": 0,
        //              "order_type": 0,
        //              "status_type": 0,
        //              "amount": 0.01,
        //              "price": 10000,
        //              "stop": 0,
        //              "id": 9244416,
        //              "initialAmount": None,
        //          },
        //      }
        //      fetchOrder, fetchOpenOrders
        //      {
        //          "pair": "BtcNis",
        //          "status": "Completed",
        //          "created": 1535555837,
        //          "type": 0,
        //          "order_type": 0,
        //          "amount": 0.00000000,
        //          "price": 120000.00000000,
        //          "stop": 0,
        //          "id": 10555173,
        //          "initialAmount": 2.00000000
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object orderUnified = null;
        Object isNewOrder = false;
        if (Helpers.isTrue(Helpers.inOp(order, "NewOrder")))
        {
            orderUnified = Helpers.GetValue(order, "NewOrder");
            isNewOrder = true;
        } else
        {
            orderUnified = order;
        }
        Object id = this.safeString(orderUnified, "id");
        Object symbol = this.safeSymbol(null, market);
        Object timestamp = this.safeIntegerProduct(orderUnified, "created", 1000);
        // status field vary between responses
        // bit2c status type:
        // 0 = New
        // 1 = Open
        // 5 = Completed
        Object status = null;
        if (Helpers.isTrue(isNewOrder))
        {
            Object tempStatus = this.safeInteger(orderUnified, "status_type");
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(tempStatus, 0)) || Helpers.isTrue(Helpers.isEqual(tempStatus, 1))))
            {
                status = "open";
            } else if (Helpers.isTrue(Helpers.isEqual(tempStatus, 5)))
            {
                status = "closed";
            }
        } else
        {
            Object tempStatus = this.safeString(orderUnified, "status");
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(tempStatus, "New")) || Helpers.isTrue(Helpers.isEqual(tempStatus, "Open"))))
            {
                status = "open";
            } else if (Helpers.isTrue(Helpers.isEqual(tempStatus, "Completed")))
            {
                status = "closed";
            }
        }
        // bit2c order type:
        // 0 = LMT,  1 = MKT
        Object type = this.safeString(orderUnified, "order_type");
        if (Helpers.isTrue(Helpers.isEqual(type, "0")))
        {
            type = "limit";
        } else if (Helpers.isTrue(Helpers.isEqual(type, "1")))
        {
            type = "market";
        }
        // bit2c side:
        // 0 = buy, 1 = sell
        Object side = this.safeString(orderUnified, "type");
        if (Helpers.isTrue(Helpers.isEqual(side, "0")))
        {
            side = "buy";
        } else if (Helpers.isTrue(Helpers.isEqual(side, "1")))
        {
            side = "sell";
        }
        Object price = this.safeString(orderUnified, "price");
        Object amount = null;
        Object remaining = null;
        if (Helpers.isTrue(isNewOrder))
        {
            amount = this.safeString(orderUnified, "amount"); // NOTE:'initialAmount' is currently not set on new order
            remaining = this.safeString(orderUnified, "amount");
        } else
        {
            amount = this.safeString(orderUnified, "initialAmount");
            remaining = this.safeString(orderUnified, "amount");
        }
        final Object finalStatus = status;
        final Object finalType = type;
        final Object finalSide = side;
        final Object finalAmount = amount;
        final Object finalRemaining = remaining;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", null );
            put( "timestamp", timestamp );
            put( "datetime", Bit2cCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", finalStatus );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", finalSide );
            put( "price", price );
            put( "triggerPrice", null );
            put( "amount", finalAmount );
            put( "filled", null );
            put( "remaining", finalRemaining );
            put( "cost", null );
            put( "trades", null );
            put( "fee", null );
            put( "info", order );
            put( "average", null );
        }}, market);
    }

